```class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int maxLen = 0, zeros = 0, ones = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s[i] == '0') zeros++;
            else ones++;
            if (zeros == ones) maxLen = max(maxLen, zeros + ones);
            else if (zeros > ones) zeros = ones = 0;
        }
        return maxLen;
    }
};
